import requests

class CloudflareAPI:
    def __init__(self, api_token, zone_id):
        self.api_token = api_token
        self.zone_id = zone_id
        self.headers = {
            "Authorization": f"Bearer {self.api_token}",
            "Content-Type": "application/json"
        }
        self.base_url = f"https://api.cloudflare.com/client/v4/zones/{self.zone_id}"

    def enable_http2(self):
        url = f"{self.base_url}/settings/http2"
        data = {"value": "on"}
        response = requests.patch(url, headers=self.headers, json=data)
        return response.json()

    def enable_http3(self):
        url = f"{self.base_url}/settings/http3"
        data = {"value": "on"}
        response = requests.patch(url, headers=self.headers, json=data)
        return response.json()

    def enable_caching(self):
        url = f"{self.base_url}/settings/cache_level"
        data = {"value": "aggressive"}
        response = requests.patch(url, headers=self.headers, json=data)
        return response.json()

    def enable_ssl(self):
        url = f"{self.base_url}/settings/ssl"
        data = {"value": "full"}
        response = requests.patch(url, headers=self.headers, json=data)
        return response.json()

    def enable_waf(self):
        url = f"{self.base_url}/firewall/settings"
        data = {"value": "on"}
        response = requests.patch(url, headers=self.headers, json=data)
        return response.json()

