using UnityEngine;

public class ProceduralEnvironmentGenerator : MonoBehaviour
{
    [Header("Terrain Settings")]
    public int width = 256;
    public int depth = 256;
    public int height = 20;
    public float scale = 20f;

    [Header("User Preferences")]
    public float preferenceInfluence = 0.5f; // Value between 0-1

    private Terrain terrain;

    void Start()
    {
        terrain = GetComponent<Terrain>();
        terrain.terrainData = GenerateTerrain(terrain.terrainData);
    }

    TerrainData GenerateTerrain(TerrainData terrainData)
    {
        terrainData.heightmapResolution = width + 1;
        terrainData.size = new Vector3(width, height, depth);
        terrainData.SetHeights(0, 0, GenerateHeights());
        return terrainData;
    }

    float[,] GenerateHeights()
    {
        float[,] heights = new float[width, depth];
        for (int x = 0; x < width; x++)
        {
            for (int z = 0; z < depth; z++)
            {
                float xCoord = (float)x / width * scale;
                float zCoord = (float)z / depth * scale;
                float baseHeight = Mathf.PerlinNoise(xCoord, zCoord);
                heights[x, z] = Mathf.Lerp(baseHeight, UserPreferenceAdjustedHeight(xCoord, zCoord), preferenceInfluence);
            }
        }
        return heights;
    }

    float UserPreferenceAdjustedHeight(float x, float z)
    {
        // Simulate user preference adjustments, could be based on user data
        // For simplicity, let's assume a basic modification
        return Mathf.PerlinNoise(x * 0.3f, z * 0.3f) + Mathf.Sin(x * 0.1f) * Mathf.Cos(z * 0.1f);
    }
}

