    def select_parents(self, population: List[str], fitness_scores: List[float]) -> Tuple[str, str]:
        # Select two parents using roulette wheel selection
        total_fitness = sum(fitness_scores)
        pick = random.uniform(0, total_fitness)
        current = 0
        for strategy, score in zip(population, fitness_scores):
            current += score
            if current > pick:
                parent1 = strategy
                break

        pick = random.uniform(0, total_fitness)
        current = 0
        for strategy, score in zip(population, fitness_scores):
            current += score
            if current > pick:
                parent2 = strategy
                break

        return parent1, parent2

    def crossover(self, parent1: str, parent2: str) -> str:
        if random.random() < self.crossover_rate:
            point = random.randint(1, len(parent1) - 1)
            return parent1[:point] + parent2[point:]
        return parent1

    def mutate(self, strategy: str) -> str:
        strategy_list = list(strategy)
        for i in range(len(strategy_list)):
            if random.random() < self.mutation_rate:
                strategy_list[i] = random.choice(['A', 'B', 'C', 'D'])
        return ''.join(strategy_list)

    def evolve(self, population: List[str]) -> List[str]:
        new_population = []
        fitness_scores = [self.fitness(strategy) for strategy in population]
        for _ in range(self.population_size // 2):
            parent1, parent2 = self.select_parents(population, fitness_scores)
            child1 = self.crossover(parent1, parent2)
            child2 = self.crossover(parent2, parent1)
            new_population.extend([self.mutate(child1), self.mutate(child2)])
        return new_population

