from genetic_algorithm import GeneticAlgorithm
from strategy_evaluation import evaluate_population

def main():
    ga = GeneticAlgorithm(population_size=100, mutation_rate=0.01, crossover_rate=0.7)
    population = ga.initialize_population()
    generations = 50

    for generation in range(generations):
        fitness_scores = evaluate_population(population)
        print(f"Generation {generation}: Best Fitness = {max(fitness_scores)}")
        population = ga.evolve(population)

    best_strategy = max(population, key=lambda x: ga.fitness(x))
    print(f"Best strategy found: {best_strategy}")

if __name__ == "__main__":
    main()
